create extension if not exists "pgcrypto";
create type friendship_status as enum ('pending','accepted','rejected');
create type channel_kind as enum ('text','voice','media','forum');
create table public.profiles (id uuid primary key references auth.users on delete cascade, username text unique not null check(char_length(username) between 3 and 24), avatar_url text, banner_url text, bio text check(char_length(bio)<=300), status text, created_at timestamptz default now());
create table public.friendships (id uuid primary key default gen_random_uuid(), requester_id uuid references profiles on delete cascade, addressee_id uuid references profiles on delete cascade, status friendship_status default 'pending', created_at timestamptz default now(), unique(requester_id,addressee_id));
create table public.blocks (blocker_id uuid references profiles on delete cascade, blocked_id uuid references profiles on delete cascade, created_at timestamptz default now(), primary key(blocker_id,blocked_id));
create table public.servers (id uuid primary key default gen_random_uuid(), owner_id uuid references profiles, name text not null, icon_url text, created_at timestamptz default now());
create table public.categories (id uuid primary key default gen_random_uuid(), server_id uuid references servers on delete cascade, name text not null, position integer default 0);
create table public.channels (id uuid primary key default gen_random_uuid(), server_id uuid references servers on delete cascade, category_id uuid references categories on delete set null, name text not null, kind channel_kind default 'text', position integer default 0, slow_mode_seconds integer default 0);
create table public.memberships (server_id uuid references servers on delete cascade, user_id uuid references profiles on delete cascade, joined_at timestamptz default now(), primary key(server_id,user_id));
create table public.roles (id uuid primary key default gen_random_uuid(), server_id uuid references servers on delete cascade, name text not null, color text, permissions bigint default 0, position integer default 0);
create table public.conversations (id uuid primary key default gen_random_uuid(), kind text not null, encrypted_room_key jsonb not null default '{}'::jsonb, created_at timestamptz default now());
create table public.conversation_members (conversation_id uuid references conversations on delete cascade, user_id uuid references profiles on delete cascade, encrypted_key text not null, joined_at timestamptz default now(), primary key(conversation_id,user_id));
create table public.encrypted_messages (id uuid primary key, conversation_id uuid references conversations on delete cascade, channel_id uuid references channels on delete cascade, sender_id uuid references profiles, client_id uuid not null, ciphertext text not null, iv text not null, algorithm text default 'AES-GCM', reply_to uuid references encrypted_messages, created_at timestamptz default now(), edited_at timestamptz, deleted_at timestamptz, unique(sender_id,client_id));
create table public.attachments (id uuid primary key default gen_random_uuid(), message_id uuid references encrypted_messages on delete cascade, object_path text not null, encrypted_key text not null, mime_type text, size_bytes bigint, created_at timestamptz default now());
create table public.themes (id uuid primary key default gen_random_uuid(), owner_id uuid references profiles on delete cascade, name text not null, manifest jsonb not null, is_public boolean default false, created_at timestamptz default now());
create table public.reports (id uuid primary key default gen_random_uuid(), reporter_id uuid references profiles, target_id uuid references profiles, decrypted_evidence jsonb, reason text not null, status text default 'open', created_at timestamptz default now());
create table public.audit_events (id bigint generated always as identity primary key, actor_id uuid references profiles, action text not null, target_type text not null, target_id text not null, metadata jsonb default '{}', created_at timestamptz default now());
alter table profiles enable row level security; alter table friendships enable row level security; alter table blocks enable row level security; alter table servers enable row level security; alter table memberships enable row level security; alter table encrypted_messages enable row level security; alter table themes enable row level security;
create policy "profiles readable" on profiles for select to authenticated using(true); create policy "profile owner updates" on profiles for update to authenticated using(auth.uid()=id);
create policy "friend participants" on friendships for all to authenticated using(auth.uid() in (requester_id,addressee_id)) with check(auth.uid() in (requester_id,addressee_id));
create policy "block owner" on blocks for all to authenticated using(auth.uid()=blocker_id) with check(auth.uid()=blocker_id);
create policy "theme owner" on themes for all to authenticated using(auth.uid()=owner_id or is_public) with check(auth.uid()=owner_id);
